record.field:
wil = env['x_work_item_line'].search([('x_product_id', 'in', records.ids), ('x_work_item_id.x_is_template', '=', True)])
for product in records:
    wil.filtered(lambda line: line.x_product_id == product).write({'x_unit_price': product.list_price, 'x_unit_cost': product.standard_price})

for wi in records:
    wi.copy(default={'x_sale_order_line_id': False, 'x_is_template': True, 'x_targeted_so_id': False})
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {'message': ', '.join(wi.x_name for wi in records) + " template saved.", 'type': 'success'},
}

if record.x_sale_order_line_id:
    record.x_sale_order_line_id.write({
        'price_unit': record.x_unit_price,
        'purchase_price': record.x_unit_cost,
    })
elif record.x_targeted_so_id:
    env['ir.actions.server'].browse(env.ref('construction_developer.server_action_create_product_for_wi').id).run()
    sol = env['sale.order.line'].create({
        'order_id': record.x_targeted_so_id.id,
        'product_id': record.x_product_id.id,
        'price_unit': record.x_unit_price,
        'purchase_price': record.x_unit_cost,
        'x_line_work_item_id': record.id,
    })
    record.write({'x_sale_order_line_id': sol.id})

for sol in records:
    wi = sol.product_id.x_work_item_template_id.copy({
        'x_sale_order_line_id': record.id,
        'x_is_template': False,
    })
    sol['x_line_work_item_id'] = wi.id
